export function buildSearchItems(navigate: (path: string) => void): CommandPaletteItem[] {
  return entries.map((entry, i) => ({
    id: `search-${i}`,
    label: entry.label,
    description: entry.description,
    icon: entry.icon,
    group: entry.group,
    tags: entry.tags,
    keywords: entry.keywords,
    onSelect: entry.external
      ? () => window.open(entry.path, '_blank', 'noopener,noreferrer')
      : () => navigate(entry.path),
  }));
}
